<?php
declare(strict_types=1);
$root = __DIR__ . '/Server/storage/releases/packages/beta';
$releases = [];
$notes = [
  '0.2.5' => ['Fixed JSON settings conversion under StrictMode.', 'Added a Windows PowerShell smoke test.'],
  '0.2.4' => ['Preserved Common-module commands after nested module imports.'],
  '0.2.3' => ['Fixed Windows PowerShell encoding compatibility.', 'Removed the module import warning.'],
  '0.2.2' => ['Added clear guidance for administrator-only actions.'],
  '0.2.1' => ['Added Start-WinTune.cmd for a simpler first launch.', 'Clarified optional beta telemetry.'],
  '0.2.0' => ['Initial signed WinTune beta release.'],
];
foreach (glob($root . '/WinTuneAdvisor-Setup-*.zip') ?: [] as $file) {
  if (!preg_match('/Setup-(\d+\.\d+\.\d+)\.zip$/', $file, $match)) continue;
  $version = $match[1];
  $releases[] = ['version' => $version, 'sha256' => strtoupper(hash_file('sha256', $file)), 'url' => '/wintune/releases/beta/' . basename($file), 'notes' => $notes[$version] ?? ['Signed beta release.']];
}
usort($releases, static fn(array $a, array $b): int => version_compare($b['version'], $a['version']));
$current = $releases[0]['version'] ?? '0.0.0';
$asset = static fn(string $path): string => (string) (@filemtime(__DIR__ . '/' . $path) ?: 1);
?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="description" content="Signed WinTune release history with checksums and download links."><title>WinTune Changelog</title><link rel="icon" href="/wintune/assets/images/favicon.png?v=<?= $asset('assets/images/favicon.png') ?>"><link rel="stylesheet" href="/wintune/assets/css/changelog.css?v=<?= $asset('assets/css/changelog.css') ?>"><script src="/wintune/assets/js/changelog.js?v=<?= $asset('assets/js/changelog.js') ?>" defer></script></head><body><header class="header wrap"><a class="brand" href="/wintune/"><img src="/wintune/assets/images/logo_wintune.png?v=<?= $asset('assets/images/logo_wintune.png') ?>" alt="WinTune"></a><nav><a href="/wintune/#principles">Principles</a><a href="/wintune/#release">Download</a><a class="active" href="/wintune/changelog/">Changelog</a><a href="https://angusu.de/docs/wintune/">Docs</a></nav><a class="source" href="https://github.com/IamAngusU/WinTune">View source ↗</a></header><main><section class="hero wrap"><p>Signed release history</p><h1>Every change,<br><span>documented.</span></h1><p class="intro">Every published build is signed, checksummed, and available for review before installation.</p><div class="facts"><div><b>Current beta</b><strong>v<?= htmlspecialchars($current) ?></strong></div><div><b>Platform</b><strong>Windows 10 / 11</strong></div><div><b>Channel</b><strong>Beta</strong></div><div><b>Source</b><strong>Reviewable</strong></div></div></section><section class="history"><div class="wrap history-grid"><div><div class="filters"><input id="search" type="search" placeholder="Search releases"><button class="selected" data-filter="all">All releases</button><button data-filter="beta">Beta</button><button data-filter="security">Security</button></div><div class="timeline"><?php foreach ($releases as $index => $release): ?><article class="release" data-search="<?= htmlspecialchars(strtolower($release['version'] . ' ' . implode(' ', $release['notes']))) ?>" data-tags="beta security"><div class="dot"></div><header><div><h2>v<?= htmlspecialchars($release['version']) ?> <?php if ($index === 0): ?><span>Latest</span><?php endif; ?></h2><p><?= htmlspecialchars($release['notes'][0]) ?></p></div><em>Signed</em></header><div class="columns"><div><b>Included</b><ul><?php foreach ($release['notes'] as $note): ?><li><?= htmlspecialchars($note) ?></li><?php endforeach; ?></ul></div><div><b>Verification</b><ul><li>RSA-SHA256 manifest</li><li>Package SHA-256</li><li>Per-file hash list</li></ul></div></div><footer><a href="<?= htmlspecialchars($release['url']) ?>" download>Download build ↓</a><a href="https://github.com/IamAngusU/WinTune/releases/tag/v<?= htmlspecialchars($release['version']) ?>">View release ↗</a><button data-copy="<?= htmlspecialchars($release['sha256']) ?>">Copy SHA-256</button></footer></article><?php endforeach; ?></div></div><aside><section><h3>Release channels</h3><p><i></i><b>Beta</b><br>New features and improvements. Explicit opt-in.</p></section><section><h3>Verify a release</h3><ol><li>Download the starter build.</li><li>Compare its SHA-256 checksum.</li><li>The launcher verifies every future update.</li></ol></section><section><h3>Transparency</h3><p>WinTune is open for review. Inspect the source before you run it.</p><a href="https://github.com/IamAngusU/WinTune">View source on GitHub ↗</a></section></aside></div></section></main></body></html>
